import{_ as a,o as e,c as r,a2 as l}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"阿尔斯通《美国陷阱》：FCPA的猎捕（2014）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/cases/ethics/alstom.md","filePath":"zh/cases/ethics/alstom.md"}'),o={name:"zh/cases/ethics/alstom.md"};function i(s,t,d,n,h,c){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="阿尔斯通《美国陷阱》-fcpa的猎捕-2014" tabindex="-1">阿尔斯通《美国陷阱》：FCPA的猎捕（2014） <a class="header-anchor" href="#阿尔斯通《美国陷阱》-fcpa的猎捕-2014" aria-label="Permalink to &quot;阿尔斯通《美国陷阱》：FCPA的猎捕（2014）&quot;">​</a></h1><p><strong>当外国企业高管成为美国司法的筹码</strong></p><blockquote><p><strong>关联指南：</strong> <a href="/zh/ethics-guide.html">商业道德、反贿赂与财务韧性指南</a> · <strong>适用行业：</strong> 能源基础设施、工程承包</p></blockquote><hr><h2 id="事件经过" tabindex="-1">事件经过 <a class="header-anchor" href="#事件经过" aria-label="Permalink to &quot;事件经过&quot;">​</a></h2><p>2013年4月，法国工业巨头阿尔斯通（Alstom）美国分公司高管弗雷德里克·皮耶鲁奇（Frédéric Pierucci）在纽约肯尼迪机场被FBI逮捕。指控内容：参与向印度尼西亚官员行贿，以换取塔拉汉（Tarahan）燃煤电厂合同。</p><p>这一事件被皮耶鲁奇本人记录在其畅销书《美国陷阱》（<em>The American Trap</em>）中，揭示了美国《境外反腐败法》（FCPA）如何被用于打击竞争对手的地缘政治工具。</p><h3 id="行贿规模与路径" tabindex="-1">行贿规模与路径 <a class="header-anchor" href="#行贿规模与路径" aria-label="Permalink to &quot;行贿规模与路径&quot;">​</a></h3><p>阿尔斯通在印尼、沙特、埃及、巴哈马等多国的项目中，通过&quot;顾问费&quot;渠道向当地官员行贿，累计金额超过<strong>7,500万美元</strong>。行贿路径：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>阿尔斯通 → 空壳顾问公司（注册于避税地） → 当地官员</span></span></code></pre></div><p>顾问公司提供虚假&quot;咨询服务&quot;，实际作用是充当行贿中间人。</p><hr><h2 id="法律结果" tabindex="-1">法律结果 <a class="header-anchor" href="#法律结果" aria-label="Permalink to &quot;法律结果&quot;">​</a></h2><table tabindex="0"><thead><tr><th>主体</th><th>结果</th></tr></thead><tbody><tr><td>阿尔斯通美国分公司</td><td>认罪，支付<strong>7.72亿美元</strong>罚款（2014年，时为FCPA史上最高罚款之一）</td></tr><tr><td>皮耶鲁奇本人</td><td>在美国联邦监狱服刑30个月</td></tr><tr><td>阿尔斯通集团</td><td>在调查期间（2014年），将能源业务出售给通用电气（GE），售价约为市场估值的低端</td></tr></tbody></table><h3 id="《美国陷阱》的争议叙事" tabindex="-1">《美国陷阱》的争议叙事 <a class="header-anchor" href="#《美国陷阱》的争议叙事" aria-label="Permalink to &quot;《美国陷阱》的争议叙事&quot;">​</a></h3><p>皮耶鲁奇认为：美国司法部有意在阿尔斯通最脆弱的时候（调查进行中）向法国政府施压，迫使法方同意将阿尔斯通能源业务出售给通用电气——这是一项对美国国家利益高度战略性的收购。</p><p>无论这一叙述是否完整，它揭示了一个关键事实：<strong>FCPA的域外管辖权极为宽泛</strong>，只要涉及美元结算、美国银行系统、美国公民或美国上市公司，美国司法部即可主张管辖。</p><hr><h2 id="同期案例对照" tabindex="-1">同期案例对照 <a class="header-anchor" href="#同期案例对照" aria-label="Permalink to &quot;同期案例对照&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公司</th><th>罚款金额</th><th>行贿地区</th></tr></thead><tbody><tr><td>西门子</td><td>8亿美元（2008）</td><td>全球多国</td></tr><tr><td>阿尔斯通</td><td>7.72亿美元（2014）</td><td>印尼、沙特等</td></tr><tr><td>罗尔斯-罗伊斯</td><td>8亿美元（2017）</td><td>印尼、中国等</td></tr><tr><td>葛兰素史克</td><td>4.9亿美元（中国，2014）</td><td>中国</td></tr></tbody></table><hr><h2 id="对供应链尽职调查的启示" tabindex="-1">对供应链尽职调查的启示 <a class="header-anchor" href="#对供应链尽职调查的启示" aria-label="Permalink to &quot;对供应链尽职调查的启示&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">第三方顾问管理是FCPA合规的重灾区</p><p>阿尔斯通案（以及大多数FCPA大案）的核心都是<strong>第三方顾问（agents/intermediaries）</strong>。以下是实务中的关键控制点：</p><p><strong>尽职调查触发条件：</strong></p><ul><li>顾问在政府项目国家有关联背景</li><li>顾问费率远高于市场水平（&quot;成功费&quot;超过合同额5%应警惕）</li><li>顾问坚持通过空壳公司或第三国账户收款</li><li>顾问无法说明其&quot;服务内容&quot;的具体价值</li></ul><p><strong>合同控制条款（必备）：</strong></p><ul><li>FCPA/UKBA/相关法律合规声明（representations &amp; warranties）</li><li>审计权条款（有权审计顾问的费用记录）</li><li>单边终止权（发现违规可立即终止合同）</li><li>禁止转包条款（顾问不得将职责转委托给第四方）</li></ul><p><strong>支付管控：</strong></p><ul><li>所有顾问费须经财务合规审批（双人签字）</li><li>禁止现金支付、禁止向第三方账户付款</li><li>付款须与可证明的服务输出挂钩，而非&quot;里程碑&quot;</li></ul></div><hr><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li>弗雷德里克·皮耶鲁奇：《美国陷阱》（<em>The American Trap</em>，2019）</li><li>美国司法部：<em>United States v. Alstom S.A.</em> — Plea Agreement (2014)</li><li>FCPA 博客：<a href="https://fcpablog.com" target="_blank" rel="noreferrer">fcpablog.com</a></li><li>GE-Alstom 并购案 EU 审查文件（2015）</li></ul>',26)])])}const m=a(o,[["render",i]]);export{u as __pageData,m as default};
